from urllib import request, error
base = 'http://localhost:5000'
paths = [
    '/flag.txt','/FLAG','/FLAG.txt','/flag','/FlAg','/static/flag','/static/flag.txt','/static/FLAG','/static/FLAG.txt','/static/.flag','/static/secret.txt','/static/keys.txt','/static/flags.txt','/static/flag.png','/static/img/flag.png','/static/img/flags.png','/static/FLAG.PNG','/flag.png','/flag.jpg','/.flag','/.FLAG']
for p in paths:
    url = base + p
    try:
        with request.urlopen(url) as resp:
            print('HIT', p, resp.getcode(), resp.info().get('Content-Type'), resp.info().get('Content-Length'))
    except error.HTTPError as e:
        if e.code != 404:
            print('CODE', p, e.code)
    except Exception as ex:
        pass
